/**
 * Phoneme timing extraction from ONNX model duration output.
 *
 * VITS models optionally output a `durations` tensor [1, phoneme_length]
 * containing the number of frames (hop_length-sized) each phoneme occupies.
 * This module converts frame counts to millisecond timestamps and provides
 * serializers for JSON, TSV, and SRT subtitle formats.
 *
 * The calculation logic and output formats are byte-for-byte compatible with
 * the Rust (`src/rust/piper-core/src/timing.rs`), Go
 * (`src/go/piperplus/timing.go`), and Python implementations so timing data
 * generated by any runtime can be consumed interchangeably.
 *
 * Browser-only module — no Node.js-specific APIs are used.
 */

/**
 * @typedef {Object} PhonemeTimingInfo
 * @property {string} phoneme - Phoneme token string
 * @property {number} start_ms - Start time in milliseconds
 * @property {number} end_ms - End time in milliseconds
 * @property {number} duration_ms - Duration in milliseconds
 */

/**
 * @typedef {Object} TimingResult
 * @property {PhonemeTimingInfo[]} phonemes - Per-phoneme timing entries
 * @property {number} total_duration_ms - Total utterance duration in milliseconds
 * @property {number} sample_rate - Audio sample rate (e.g. 22050)
 */

/**
 * Default STFT hop length for VITS models (samples).
 * @type {number}
 */
export const DEFAULT_HOP_LENGTH = 256;

/**
 * Convert per-phoneme duration frames from the ONNX model's duration output
 * to millisecond timestamps.
 *
 * Calculation matches the Rust/Go/Python implementations exactly:
 *   frame_time_ms = (hop_length / sample_rate) * 1000
 *   for each duration:
 *     duration_ms = max(frames, 0) * frame_time_ms
 *     start_ms = cursor_ms
 *     end_ms = cursor_ms + duration_ms
 *     cursor_ms = end_ms
 *
 * @param {Float32Array | number[] | { length: number, [index: number]: number }} durations
 *   Duration values from the ONNX output tensor. Accepts Float32Array, plain
 *   Array, or any indexable object with a `length` property.
 * @param {number} sampleRate - Audio sample rate (must be > 0)
 * @param {number} [hopLength=DEFAULT_HOP_LENGTH] - STFT hop length (must be > 0)
 * @param {string[] | null} [phonemeTokens=null] - Optional phoneme token strings.
 *   If null, indices are formatted as `ph_${i}`. If provided, length must match
 *   `durations.length`.
 * @returns {TimingResult}
 * @throws {Error} If `sampleRate <= 0`, `hopLength <= 0`, or `phonemeTokens`
 *   length differs from `durations` length.
 */
export function durationsToTiming(
  durations,
  sampleRate,
  hopLength = DEFAULT_HOP_LENGTH,
  phonemeTokens = null,
) {
  if (!Number.isFinite(sampleRate) || sampleRate <= 0) {
    throw new TypeError(`sampleRate must be a positive finite number (Hz), got ${sampleRate}`);
  }
  if (!Number.isFinite(hopLength) || hopLength <= 0) {
    throw new TypeError(`hopLength must be a positive finite number (samples), got ${hopLength}`);
  }
  if (durations == null || typeof durations.length !== 'number') {
    throw new TypeError(
      'durations must be a Float32Array, Array, or indexable with a numeric length property',
    );
  }

  const length = durations.length;

  if (phonemeTokens != null) {
    if (!Array.isArray(phonemeTokens)) {
      throw new TypeError('phonemeTokens must be an array of strings');
    }
    if (phonemeTokens.length !== length) {
      throw new RangeError(
        `length mismatch: durations has ${length} elements but phonemeTokens has ${phonemeTokens.length}`,
      );
    }
  }

  const frameTimeMs = (hopLength / sampleRate) * 1000;

  /** @type {PhonemeTimingInfo[]} */
  const phonemes = new Array(length);
  let cursorMs = 0;
  let totalDurationMs = 0;

  const hasTokens = phonemeTokens != null;
  for (let i = 0; i < length; i++) {
    const raw = durations[i];
    if (raw < 0) {
      globalThis.console?.warn?.(
        `negative phoneme duration clamped to 0 (index=${i}, value=${raw})`,
      );
    }
    const frames = raw > 0 ? raw : 0;
    const durationMs = frames * frameTimeMs;
    const startMs = cursorMs;
    const endMs = cursorMs + durationMs;

    const token = hasTokens ? phonemeTokens[i] : `ph_${i}`;

    phonemes[i] = {
      phoneme: token,
      start_ms: startMs,
      end_ms: endMs,
      duration_ms: durationMs,
    };

    cursorMs = endMs;
    totalDurationMs += durationMs;
  }

  return {
    phonemes,
    total_duration_ms: totalDurationMs,
    sample_rate: sampleRate,
  };
}

/**
 * Serialize a TimingResult as pretty-printed JSON (2-space indent).
 * @param {TimingResult} result
 * @returns {string}
 */
export function timingToJson(result) {
  return JSON.stringify(result, null, 2);
}

/**
 * Serialize a TimingResult as compact (single-line) JSON.
 * @param {TimingResult} result
 * @returns {string}
 */
export function timingToJsonCompact(result) {
  return JSON.stringify(result);
}

/**
 * Serialize a TimingResult as tab-separated values with a header line.
 * Output matches the Rust/Go format: `start_ms\tend_ms\tduration_ms\tphoneme\n`
 * with floats formatted via `toFixed(3)` and trailing newline on every row.
 *
 * Tabs and newlines inside phoneme strings are escaped to `\t` / `\n` to
 * preserve the TSV structure (matches the Go implementation).
 *
 * @param {TimingResult} result
 * @returns {string}
 */
export function timingToTsv(result) {
  const rows = new Array(result.phonemes.length + 1);
  rows[0] = 'start_ms\tend_ms\tduration_ms\tphoneme';
  for (let i = 0; i < result.phonemes.length; i++) {
    const p = result.phonemes[i];
    const escaped = String(p.phoneme).replace(/\t/g, '\\t').replace(/\n/g, '\\n');
    rows[i + 1] = `${p.start_ms.toFixed(3)}\t${p.end_ms.toFixed(3)}\t${p.duration_ms.toFixed(3)}\t${escaped}`;
  }
  return rows.join('\n') + '\n';
}

/**
 * Serialize a TimingResult as an SRT-like subtitle file. Each phoneme becomes
 * a numbered cue with `HH:MM:SS,mmm` timestamps. Output matches the Rust
 * implementation byte-for-byte.
 *
 * @param {TimingResult} result
 * @returns {string}
 */
export function timingToSrt(result) {
  let buf = '';
  for (let i = 0; i < result.phonemes.length; i++) {
    const p = result.phonemes[i];
    const idx = i + 1;
    const start = formatSrtTimestamp(p.start_ms);
    const end = formatSrtTimestamp(p.end_ms);
    buf += `${idx}\n${start} --> ${end}\n${p.phoneme}\n\n`;
  }
  return buf;
}

/**
 * Format a millisecond value as an SRT timestamp `HH:MM:SS,mmm`.
 * Mirrors the Rust `format_srt_timestamp` helper: round the input, then
 * decompose into hours/minutes/seconds/milliseconds with zero padding.
 *
 * @param {number} ms
 * @returns {string}
 */
function formatSrtTimestamp(ms) {
  const totalMs = Math.round(ms);
  const millis = totalMs % 1000;
  const totalSecs = Math.floor(totalMs / 1000);
  const secs = totalSecs % 60;
  const totalMins = Math.floor(totalSecs / 60);
  const mins = totalMins % 60;
  const hours = Math.floor(totalMins / 60);

  const hh = String(hours).padStart(2, '0');
  const mm = String(mins).padStart(2, '0');
  const ss = String(secs).padStart(2, '0');
  const mmm = String(millis).padStart(3, '0');
  return `${hh}:${mm}:${ss},${mmm}`;
}


/**
 * Build a reverse lookup map from phoneme ID to phoneme token string.
 *
 * Given a model config's `phoneme_id_map` (phoneme string → list of IDs),
 * returns a flat map of ID → phoneme string for efficient reverse lookup.
 * When multiple IDs point to the same phoneme, the first occurrence wins.
 *
 * PUA (Private Use Area, U+E000–U+F8FF) characters without an explicit
 * `puaToMultiChar` mapping are rendered as `U+XXXX` for readability.
 *
 * This matches the Python `build_phoneme_id_reverse_map()` behavior.
 *
 * @param {Record<string, number[]>} phonemeIdMap - Config's phoneme_id_map
 * @param {Record<string, string> | null} [puaToMultiChar=null] - Optional
 *   PUA char → multi-char name mapping (e.g. `{"\uE019": "N_m"}`)
 * @returns {Record<number, string>} ID → display name
 */
export function buildPhonemeIdToTokenMap(phonemeIdMap, puaToMultiChar = null) {
  const reverse = {};
  if (!phonemeIdMap) return reverse;

  for (const [char, ids] of Object.entries(phonemeIdMap)) {
    if (!Array.isArray(ids)) continue;

    // Determine display name for this character.
    let display = char;
    if (puaToMultiChar && puaToMultiChar[char] !== undefined) {
      display = puaToMultiChar[char];
    } else if (char.length === 1) {
      const code = char.charCodeAt(0);
      if (code >= 0xE000 && code <= 0xF8FF) {
        display = `U+${code.toString(16).toUpperCase().padStart(4, '0')}`;
      }
    }

    for (const id of ids) {
      if (typeof id === 'number' && !(id in reverse)) {
        reverse[id] = display;
      }
    }
  }

  return reverse;
}
